class Solution {
    public int maxAreaOfIsland(int[][] grid) {
        int best = 0;
        for (int r = 0; r < grid.length; r++) {
            for (int c = 0; c < grid[0].length; c++) {
                if (grid[r][c] == 1) {
                    best = Math.max(best, dfs(grid, r, c));
                }
            }
        }
        return best;
    }

    private int dfs(int[][] grid, int r, int c) {
        if (r < 0 || c < 0 || r >= grid.length || c >= grid[0].length || grid[r][c] == 0) return 0;
        grid[r][c] = 0;
        return 1 + dfs(grid, r + 1, c) + dfs(grid, r - 1, c) + dfs(grid, r, c + 1) + dfs(grid, r, c - 1);
    }
}

class Solution {
    public int findCircleNum(int[][] isConnected) {
        int n = isConnected.length;
        boolean[] visited = new boolean[n];
        int provinces = 0;
        for (int i = 0; i < n; i++) {
            if (!visited[i]) {
                provinces++;
                dfs(isConnected, visited, i);
            }
        }
        return provinces;
    }

    private void dfs(int[][] isConnected, boolean[] visited, int city) {
        visited[city] = true;
        for (int neighbor = 0; neighbor < isConnected.length; neighbor++) {
            if (isConnected[city][neighbor] == 1 && !visited[neighbor]) {
                dfs(isConnected, visited, neighbor);
            }
        }
    }
}

class Solution {
    private int[][] dirs = {{1,0},{-1,0},{0,1},{0,-1}};

    public List<List<Integer>> pacificAtlantic(int[][] heights) {
        int rows = heights.length, cols = heights[0].length;
        boolean[][] pacific = new boolean[rows][cols];
        boolean[][] atlantic = new boolean[rows][cols];

        for (int r = 0; r < rows; r++) {
            dfs(heights, pacific, r, 0);
            dfs(heights, atlantic, r, cols - 1);
        }
        for (int c = 0; c < cols; c++) {
            dfs(heights, pacific, 0, c);
            dfs(heights, atlantic, rows - 1, c);
        }

        List<List<Integer>> result = new ArrayList<>();
        for (int r = 0; r < rows; r++) {
            for (int c = 0; c < cols; c++) {
                if (pacific[r][c] && atlantic[r][c]) {
                    result.add(Arrays.asList(r, c));
                }
            }
        }
        return result;
    }

    private void dfs(int[][] heights, boolean[][] reach, int r, int c) {
        reach[r][c] = true;
        for (int[] d : dirs) {
            int nr = r + d[0], nc = c + d[1];
            if (nr >= 0 && nc >= 0 && nr < heights.length && nc < heights[0].length
                    && !reach[nr][nc] && heights[nr][nc] >= heights[r][c]) {
                dfs(heights, reach, nr, nc);
            }
        }
    }
}

class Solution {
    public boolean canFinish(int numCourses, int[][] prerequisites) {
        List<List<Integer>> adj = new ArrayList<>();
        for (int i = 0; i < numCourses; i++) adj.add(new ArrayList<>());
        for (int[] p : prerequisites) adj.get(p[0]).add(p[1]);

        int[] state = new int[numCourses]; // 0 = unvisited, 1 = visiting, 2 = done
        for (int course = 0; course < numCourses; course++) {
            if (state[course] == 0 && hasCycle(course, adj, state)) return false;
        }
        return true;
    }

    private boolean hasCycle(int course, List<List<Integer>> adj, int[] state) {
        state[course] = 1;
        for (int prereq : adj.get(course)) {
            if (state[prereq] == 1) return true;
            if (state[prereq] == 0 && hasCycle(prereq, adj, state)) return true;
        }
        state[course] = 2;
        return false;
    }
}

class Solution {
    public int[] findOrder(int numCourses, int[][] prerequisites) {
        List<List<Integer>> adj = new ArrayList<>();
        for (int i = 0; i < numCourses; i++) adj.add(new ArrayList<>());
        for (int[] p : prerequisites) adj.get(p[0]).add(p[1]);

        int[] state = new int[numCourses];
        LinkedList<Integer> order = new LinkedList<>();
        for (int course = 0; course < numCourses; course++) {
            if (state[course] == 0 && !dfs(course, adj, state, order)) {
                return new int[0];
            }
        }
        int[] result = new int[order.size()];
        for (int i = 0; i < result.length; i++) result[i] = order.get(i);
        return result;
    }

    private boolean dfs(int course, List<List<Integer>> adj, int[] state, LinkedList<Integer> order) {
        state[course] = 1;
        for (int prereq : adj.get(course)) {
            if (state[prereq] == 1) return false;
            if (state[prereq] == 0 && !dfs(prereq, adj, state, order)) return false;
        }
        state[course] = 2;
        order.addFirst(course);
        return true;
    }
}

class Solution {
    public int[] sortItems(int n, int m, int[] group, List<List<Integer>> beforeItems) {
        int groupCount = m;
        for (int i = 0; i < n; i++) {
            if (group[i] == -1) group[i] = groupCount++;
        }

        List<List<Integer>> itemGraph = new ArrayList<>();
        List<List<Integer>> groupGraph = new ArrayList<>();
        for (int i = 0; i < n; i++) itemGraph.add(new ArrayList<>());
        for (int i = 0; i < groupCount; i++) groupGraph.add(new ArrayList<>());

        int[] itemIndegree = new int[n];
        int[] groupIndegree = new int[groupCount];

        for (int item = 0; item < n; item++) {
            for (int pre : beforeItems.get(item)) {
                itemGraph.get(pre).add(item);
                itemIndegree[item]++;
                if (group[pre] != group[item]) {
                    groupGraph.get(group[pre]).add(group[item]);
                    groupIndegree[group[item]]++;
                }
            }
        }

        List<Integer> itemOrder = topoSort(itemGraph, itemIndegree, n);
        List<Integer> groupOrder = topoSort(groupGraph, groupIndegree, groupCount);
        if (itemOrder == null || groupOrder == null) return new int[0];

        Map<Integer, List<Integer>> itemsByGroup = new HashMap<>();
        for (int item : itemOrder) {
            itemsByGroup.computeIfAbsent(group[item], k -> new ArrayList<>()).add(item);
        }

        int[] result = new int[n];
        int idx = 0;
        for (int g : groupOrder) {
            for (int item : itemsByGroup.getOrDefault(g, new ArrayList<>())) {
                result[idx++] = item;
            }
        }
        return result;
    }

    private List<Integer> topoSort(List<List<Integer>> graph, int[] indegree, int total) {
        Queue<Integer> queue = new LinkedList<>();
        for (int i = 0; i < total; i++) {
            if (indegree[i] == 0) queue.offer(i);
        }
        List<Integer> order = new ArrayList<>();
        while (!queue.isEmpty()) {
            int node = queue.poll();
            order.add(node);
            for (int next : graph.get(node)) {
                if (--indegree[next] == 0) queue.offer(next);
            }
        }
        return order.size() == total ? order : null;
    }
}

